"""Resolve per-repo workflow mode from ``.rebaseai/config.yaml``."""

from __future__ import annotations

import base64
import logging
import re
from pathlib import Path
from typing import Literal
from urllib.parse import quote

import requests

RepoMode = Literal["legacy", "domain-driven"]

_CONFIG_REL_PATH = ".rebaseai/config.yaml"
_VALID_MODES: frozenset[str] = frozenset({"legacy", "domain-driven"})
_MODE_LINE = re.compile(r"^mode\s*:\s*(.+?)\s*$", re.IGNORECASE)

logger = logging.getLogger(__name__)


def normalize_mode(raw: str | None) -> RepoMode:
    """Map config text to a validated repo mode; absent/invalid values default to legacy."""
    if raw is None:
        return "legacy"
    value = raw.strip().strip('"').strip("'")
    if value in _VALID_MODES:
        return value  # type: ignore[return-value]
    if value:
        logger.warning("invalid repo mode %r; defaulting to legacy", value)
    return "legacy"


def parse_mode_from_config_yaml(text: str) -> RepoMode:
    """Parse ``mode`` from YAML config body; defaults to legacy when absent."""
    for line in text.splitlines():
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            continue
        match = _MODE_LINE.match(stripped)
        if match:
            return normalize_mode(match.group(1))
    return "legacy"


def resolve_repo_mode_from_path(config_path: Path) -> RepoMode:
    """Read mode from a local ``.rebaseai/config.yaml`` path."""
    if not config_path.is_file():
        return "legacy"
    try:
        text = config_path.read_text(encoding="utf-8")
    except OSError as exc:
        logger.warning("could not read %s: %s; defaulting to legacy", config_path, exc)
        return "legacy"
    return parse_mode_from_config_yaml(text)


def resolve_repo_mode_from_github(
    owner: str,
    repo: str,
    *,
    token: str | None = None,
    session: requests.Session | None = None,
) -> RepoMode:
    """Fetch mode via GitHub contents API before clone (cheap dispatch-time read)."""
    owner = owner.strip()
    repo = repo.strip()
    if not owner or not repo:
        raise ValueError("owner and repo are required")

    path = quote(_CONFIG_REL_PATH, safe="/")
    url = f"https://api.github.com/repos/{owner}/{repo}/contents/{path}"
    headers = {"Accept": "application/vnd.github+json"}
    if token:
        headers["Authorization"] = f"Bearer {token.strip()}"

    http = session or requests
    try:
        response = http.get(url, headers=headers, timeout=30)
    except requests.RequestException as exc:
        logger.warning("GitHub contents API failed for %s/%s: %s", owner, repo, exc)
        return "legacy"

    if response.status_code == 404:
        return "legacy"
    if response.status_code != 200:
        logger.warning(
            "GitHub contents API returned %s for %s/%s; defaulting to legacy",
            response.status_code,
            owner,
            repo,
        )
        return "legacy"

    payload = response.json()
    content_b64 = payload.get("content")
    if not isinstance(content_b64, str) or not content_b64.strip():
        return "legacy"

    try:
        decoded = base64.b64decode(content_b64, validate=False).decode("utf-8")
    except (UnicodeDecodeError, ValueError) as exc:
        logger.warning("could not decode config for %s/%s: %s", owner, repo, exc)
        return "legacy"
    return parse_mode_from_config_yaml(decoded)


def assert_repo_mode_matches(expected: RepoMode, actual: RepoMode) -> None:
    """Fail fast when dispatch-time mode disagrees with post-clone config."""
    if expected != actual:
        raise ValueError(
            f"repo mode mismatch: dispatched as {expected!r} but clone has {actual!r}"
        )

"""Workflow pack path resolution for domain-driven workflows (no environment reads)."""

from __future__ import annotations

from pathlib import Path

DOMAIN_BOOTSTRAP_WORKFLOW_DIR_ENV = "DOMAIN_BOOTSTRAP_WORKFLOW_DIR"
DOMAIN_ISSUE_WORKFLOW_DIR_ENV = "DOMAIN_ISSUE_WORKFLOW_DIR"
DOMAIN_DESIGN_WORKFLOW_DIR_ENV = "DOMAIN_DESIGN_WORKFLOW_DIR"

_WORKFLOWS_ROOT = Path(__file__).resolve().parent.parent.parent / "workflows"


def default_bootstrap_pack_root() -> Path:
    return _WORKFLOWS_ROOT / "domain-bootstrap"


def default_issue_pack_root() -> Path:
    return _WORKFLOWS_ROOT / "domain-issue"


def default_design_pack_root() -> Path:
    return _WORKFLOWS_ROOT / "domain-design"


def resolve_bootstrap_pack_root(override_dir: str) -> Path:
    raw = override_dir.strip()
    return Path(raw).expanduser() if raw else default_bootstrap_pack_root()


def resolve_issue_pack_root(override_dir: str) -> Path:
    raw = override_dir.strip()
    return Path(raw).expanduser() if raw else default_issue_pack_root()


def resolve_design_pack_root(override_dir: str) -> Path:
    raw = override_dir.strip()
    return Path(raw).expanduser() if raw else default_design_pack_root()


def workflow_yaml_path(pack_root: Path) -> Path:
    return pack_root / "workflow.yaml"

