def _fetch_prompts(
    client: LangfusePromptClient,
    opts: LangfusePromptOptions,
    *,
    names: dict[str, str],
) -> dict[str, str]:
    return {
        placeholder: prompt_text(
            client,
            langfuse_name,
            label=opts.label,
            cache_ttl_seconds=opts.cache_ttl_seconds,
        )
        for placeholder, langfuse_name in names.items()
    }


def fetch_domain_bootstrap_prompts_for_credentials(
    *,
    public_key: str,
    secret_key: str,
    base_url: str,
