"""Shared helpers for domain-driven flow runners."""

from __future__ import annotations

import re
from pathlib import Path

from agents.flow_cli import run_flow_async, sanitize_source_repo
from agents.flow_workflow import (
    flow_log_tail,
    prepare_run_directory,
    resolve_pr_link,
    substitute_langfuse_tokens,
)

_ISSUE_REF_PATTERN = re.compile(r"(?:^|#)(\d+)$|/issues/(\d+)")


def parse_issue_ref(raw: str) -> str:
    """Normalize issue ref to a numeric string for workflow params."""
    text = (raw or "").strip()
    if not text:
        raise ValueError("issue_ref is required")
    if text.isdigit():
        return text
    match = _ISSUE_REF_PATTERN.search(text)
    if match:
        number = match.group(1) or match.group(2)
        if number:
            return number
    raise ValueError(f"issue_ref must be a number or GitHub issue URL, got: {raw!r}")


def validate_placeholders(yaml_source: str, tokens: tuple[str, ...]) -> None:
    for token in tokens:
        if token not in yaml_source:
            raise ValueError(f"workflow YAML is missing required token: {token}")


def render_workflow_yaml(
    yaml_source: str,
    prompts: dict[str, str],
    *,
    required_tokens: tuple[str, ...],
) -> str:
    validate_placeholders(yaml_source, required_tokens)
    return substitute_langfuse_tokens(yaml_source, prompts)


async def invoke_flow_pack(
    *,
    pack_root: Path,
    yaml_source: str,
    prompts: dict[str, str],
    workflow_name: str,
    params: dict[str, str],
    github_token: str,
    required_tokens: tuple[str, ...],
) -> tuple[int, Path, Path, str | None]:
    """Prepare run dir, invoke flow, return exit code, paths, and optional PR URL."""
    rendered = render_workflow_yaml(yaml_source, prompts, required_tokens=required_tokens)
    run_dir, rendered_path = prepare_run_directory(
        pack_root=pack_root,
        yaml_source=yaml_source,
        prompts=prompts,
        workflow_name=workflow_name,
    )
    log_path = run_dir / "flow.log"
    exit_code = await run_flow_async(
        workflow_yaml=rendered_path,
        cwd=run_dir,
        params=params,
        log_path=log_path,
        env={"GITHUB_TOKEN": github_token},
    )
    pr_url: str | None = None
    if exit_code == 0:
        pr_url = resolve_pr_link(run_dir, log_path=log_path)
    return exit_code, run_dir, log_path, pr_url


def read_artifact_json(run_dir: Path, name: str) -> dict[str, object]:
    import json

    path = run_dir / "artifacts" / name
    if not path.is_file():
        raise FileNotFoundError(f"missing artifact: {path}")
    data = json.loads(path.read_text(encoding="utf-8"))
    if not isinstance(data, dict):
        raise ValueError(f"{name} must be a JSON object")
    return data


def read_text_artifact(run_dir: Path, name: str) -> str:
    path = run_dir / "artifacts" / name
    if not path.is_file():
        raise FileNotFoundError(f"missing artifact: {path}")
    return path.read_text(encoding="utf-8")


def flow_log_tail_text(log_path: Path) -> str | None:
    return flow_log_tail(log_path) if log_path.is_file() else None


def sanitize_repo(raw: str) -> str:
    return sanitize_source_repo(raw)

