"""Unit tests for domain-driven Langfuse prompt mapping."""

from __future__ import annotations

from unittest.mock import MagicMock

import pytest

from agents.domain_driven.langfuse_prompts import (
    ARCHITECT_PROMPT_PLACEHOLDER,
    DOMAIN_DESIGNER_PROMPT_PLACEHOLDER,
    fetch_domain_bootstrap_prompts,
    fetch_domain_design_prompts,
    fetch_domain_issue_prompts,
)
from agents.architecture_design.langfuse_prompts import REVIEWER_PROMPT_PLACEHOLDER


class _FakePrompt:
    def __init__(self, text: str) -> None:
        self.prompt = text


@pytest.fixture
def fake_langfuse() -> MagicMock:
    client = MagicMock()

    def get_prompt(
        name: str,
        *,
        label: str,
        cache_ttl_seconds: int | None = None,
    ) -> _FakePrompt:
        bodies = {
            "domain-driven/architect": "ARCHITECT",
            "domain-driven/domain-designer": "DESIGNER",
            "architecture-design/reviewer": "REVIEWER",
        }
        return _FakePrompt(bodies[name])

    client.get_prompt.side_effect = get_prompt
    return client


def test_fetch_domain_bootstrap_prompts(fake_langfuse: MagicMock) -> None:
    monkeypatch = pytest.MonkeyPatch()
    monkeypatch.setenv("LANGFUSE_PROMPT_LABEL", "production")
    prompts = fetch_domain_bootstrap_prompts(fake_langfuse)
    assert prompts[ARCHITECT_PROMPT_PLACEHOLDER] == "ARCHITECT"
    assert prompts[REVIEWER_PROMPT_PLACEHOLDER] == "REVIEWER"
    monkeypatch.undo()


def test_fetch_domain_design_prompts(fake_langfuse: MagicMock) -> None:
    prompts = fetch_domain_design_prompts(fake_langfuse)
    assert prompts[DOMAIN_DESIGNER_PROMPT_PLACEHOLDER] == "DESIGNER"


def test_fetch_domain_issue_prompts(fake_langfuse: MagicMock) -> None:
    prompts = fetch_domain_issue_prompts(fake_langfuse)
    assert prompts[ARCHITECT_PROMPT_PLACEHOLDER] == "ARCHITECT"

